ProgramBlock.ScriptSource:
// ===================================================================
// CONTEXT ENGINE - SYSTEM UTILITY
// ===================================================================
// This service generates dynamic prompts for LLM handlers.
// It populates templates with the list of controllable devices and
// current system status (Weather, Energy, Security, and live states).
// ===================================================================

Api.Handle("System.Utility/ContextEngine", (args) => {
    var request = Api.Parse(args);
    string template = (string)request.Data;

    if (string.IsNullOrEmpty(template))
    {
        template = "**AVAILABLE MODULES**\n\n%%AVAILABLE_DEVICES%%\n**CURRENT SYSTEM STATUS** (Timestamp: %%CURRENT_TIME%%)\n\n%%SYSTEM_STATUS%%\n";
    }

    // --- 1. COLLECT USER-CONFIGURED MODULES ---
    // We create a unified list of ModuleHelpers that the user is allowed to control.
    var controlModules = new List<ModuleHelper>();
    var sensorModules = new List<ModuleHelper>();

    // Physical devices (Lights, Switches, Thermostats, etc.)
    string allowedTypes = "Dimmer,Light,Color,Switch,Shutter,DoorLock,Thermostat,Sensor,DoorWindow";
    Modules.OfDeviceType(allowedTypes).Each((m) => {
        var instance = m.Instance;
        var deviceType = instance.DeviceType.ToString().ToLower();
        if ((deviceType == "sensor" || deviceType == "doorwindow") && instance.Domain != "HomeAutomation.SecuritySystem")
        {
            sensorModules.Add(m);
            // the only "Sensor" listed in 'controlModules' is Security Alarm System
        } else {
            controlModules.Add(m);
        }
        return false; // Continue iteration
    });

    // Scenarios and Macros (Programs configured with the generic program widget)
    Modules.OfDeviceType("Program").WithParameter("Widget.DisplayModule").Each((m) => {
        // Filter out system loggers and ensure it's a user-facing program
        var widget = m.Parameter("Widget.DisplayModule")?.Value;
        if (m.Instance.Address != "6" && m.Instance.Address != "7"
            && m.Instance.Address != "34" && m.Instance.Address != "940"
            && !String.IsNullOrWhiteSpace(widget))
        {
            controlModules.Add(m);
        }
        return false;
    });

    // --- 2. GENERATE AVAILABLE DEVICES LIST (Directory) ---
    // This section provides the AI with a clean list of IDs and types.
    // Live states (ON/OFF) are NOT included here to keep the list stable.
    var devicesSb = new StringBuilder();
    foreach (var m in controlModules) {
        var module = m.Instance;
        var type = module.DeviceType.ToString();
        // exception
        if (type == "Program" && m.Parameter("Widget.DisplayModule").Value != "homegenie/generic/program")
        {
            type = m.Parameter("Widget.DisplayModule").Value;
            if (type.LastIndexOf("/") > 0)
            {
                type = type.Substring(type.LastIndexOf("/") + 1);
            }
        }

        var moduleGroups = Modules.Groups
            .Where(g => Modules.InGroup(g).SelectedModules.Any(mod =>
                mod.Domain == module.Domain &&
                mod.Address == module.Address))
            .ToList();

        var groups = string.Join(", ", moduleGroups);
        if (string.IsNullOrEmpty(groups))
        {
            groups = "(unassigned)";
        }

        devicesSb.AppendLine($"- {module.Name} | {type} | {module.Domain}/{module.Address} | " + groups);
    }

    // --- 3. GENERATE SYSTEM STATUS REPORT (Live Context) ---
    // This section provides the AI with real-time situational awareness.
    var statusSb = new StringBuilder();

    // A. Core System Reports (Weather, Energy, Alarm, Master Thermostat)
    statusSb.AppendLine("## SYSTEM REPORT");

    var weather = Modules.InDomain("HomeAutomation.HomeGenie.Automation").WithAddress("34").Get();
    if (weather.Instance != null) statusSb.AppendLine("- " + PromptHelpers.GetWeatherStatus(weather));

    var energy = Modules.InDomain("HomeAutomation.EnergyMonitor").WithAddress("1").Get();
    if (energy.Instance != null) statusSb.AppendLine("- " + PromptHelpers.GetEnergyStatus(energy));

    var alarm = Modules.InDomain("HomeAutomation.SecuritySystem").WithAddress("Main").Get();
    if (alarm.Instance != null) statusSb.AppendLine("- " + PromptHelpers.GetSecurityStatus(alarm));

    var thermo = Modules.InDomain("HomeAutomation.SmartThermostat").WithAddress("1").Get();
    if (thermo.Instance != null) statusSb.AppendLine("- " + PromptHelpers.GetThermostatStatus(thermo));

    // B. Individual Devices Live Status
    // Provides a 1:1 status update for the devices listed in the directory.
    statusSb.AppendLine("\n## DEVICES STATUS");
    foreach (var m in controlModules) {
        var info = PromptHelpers.GetModuleStatus(m);
        if (!string.IsNullOrEmpty(info)) statusSb.AppendLine("- " + info);
    }
    statusSb.AppendLine("\n## SENSORS STATUS");
    foreach (var m in sensorModules) {
        var info = PromptHelpers.GetModuleStatus(m);
        if (!string.IsNullOrEmpty(info)) statusSb.AppendLine("- " + info);
    }

    // --- 4. TEMPLATE ASSEMBLY ---
    // Replace placeholders with generated content and current server time.
    return template
        .Replace("%%AVAILABLE_DEVICES%%", devicesSb.ToString())
        .Replace("%%SYSTEM_STATUS%%", statusSb.ToString())
        .Replace("%%CURRENT_TIME%%", DateTime.Now.ToString("f", System.Globalization.CultureInfo.InvariantCulture)
        + "\n--- END OF SYSTEM REPORT ---\n\n");
});

// Run in background to stay available for LLM handler requests
Program.GoBackground();

ProgramBlock.ScriptContext:
public static class PromptHelpers
{
    /**
     * Helper to format double values for the AI.
     * Ensures the dot is always used as the decimal separator (Invariant Culture).
     */
    public static string Fmt(double val, string unit = "")
    {
        if (double.IsNaN(val) || double.IsInfinity(val)) return "N/A";
        return val.ToString("F1", CultureInfo.InvariantCulture) + unit;
    }

    /**
     * Extracts weather conditions, exterior temperature, and wind speed.
     */
    public static string GetWeatherStatus(ModuleHelper m)
    {
        var condition = m.Parameter("Conditions.Status").Value;
        if (string.IsNullOrWhiteSpace(condition)) condition = m.Parameter("Conditions.Description").Value;

        var temp = Fmt(m.Parameter("Sensor.Temperature").DecimalValue, "°C");
        var wind = Fmt(m.Parameter("Sensor.Wind.Speed").DecimalValue, " Kph");

        return $"Weather: {(string.IsNullOrEmpty(condition) ? "Unknown" : condition)} | Exterior Temp: {temp} | Wind: {wind}";
    }

    /**
     * Summarizes energy load, daily usage, and active device counts.
     */
    public static string GetEnergyStatus(ModuleHelper m)
    {
        var load = Fmt(m.Parameter("EnergyMonitor.WattLoad").DecimalValue, "W");
        var todayKwh = (m.Parameter("EnergyMonitor.WattCounter.Today").DecimalValue / 1000.0).ToString("F2", CultureInfo.InvariantCulture) + " kWh";

        var lights = m.Parameter("EnergyMonitor.OperatingLights").Value;
        var appliances = m.Parameter("EnergyMonitor.OperatingSwitches").Value;

        return $"Energy: Load {load} | Today's Usage: {todayKwh} (Active -> Lights: {lights}, Appliances: {appliances})";
    }

    /**
     * Reports the alarm arming mode and whether the security system is currently triggered.
     */
    public static string GetSecurityStatus(ModuleHelper m)
    {
        var state = m.Parameter("HomeGenie.SecurityArmed").Value;
        var triggered = m.Parameter("HomeGenie.SecurityTriggered").DecimalValue > 0 ? " !!ALARM TRIGGERED!!" : "";

        return $"Security: System is {state}{triggered}";
    }

    /**
     * Reports ambient temperature, target setpoint, and the current operating state.
     */
    public static string GetThermostatStatus(ModuleHelper m)
    {
        var ambient = Fmt(m.Parameter("Sensor.Temperature").DecimalValue, "°C");
        var target = Fmt(m.Parameter("Thermostat.SetPoint.Heating").DecimalValue, "°C");
        var state = m.Parameter("Thermostat.OperatingState").Value;
        var mode = m.Parameter("Thermostat.Mode").Value;

        return $"Thermostat: Ambient {ambient} | Target {target} (Mode: {mode}, State: {state})";
    }

    /**
     * Extracts a concise status string for any module (Sensors, Actuators, or Programs).
     * Used for the dynamic System Update/Status report.
     */
    public static string GetModuleStatus(ModuleHelper m)
    {
        // Skip modules with no name to keep the prompt clean
        if (string.IsNullOrWhiteSpace(m.Instance.Name)) return "";

        var statusParts = new List<string>();

        // 1. PROGRAMS (Scenarios/Macros)
        if (m.Instance.DeviceType.ToString() == "Program")
        {
            var pStatus = m.Parameter("Program.Status").Value;
            statusParts.Add("Status: " + (string.IsNullOrEmpty(pStatus) ? "Idle" : pStatus));
        }

        // 2. SENSORS (Environmental parameters)
        if (m.HasParameter("Sensor.Temperature"))
            statusParts.Add("Temp: " + Fmt(m.Parameter("Sensor.Temperature").DecimalValue, "°C"));

        if (m.HasParameter("Sensor.Humidity"))
            statusParts.Add("Hum: " + Fmt(m.Parameter("Sensor.Humidity").DecimalValue, "%"));

        if (m.HasParameter("Sensor.Luminance"))
            statusParts.Add("Luminance: " + m.Parameter("Sensor.Luminance").Value + " lux");

        if (m.HasParameter("Sensor.Motion"))
            statusParts.Add("Motion: " + (m.Parameter("Sensor.Motion").DecimalValue > 0 ? "Detected" : "None"));

        if (m.HasParameter("Meter.Watts"))
            statusParts.Add("Watts: " + Fmt(m.Parameter("Meter.Watts").DecimalValue, "W"));

        if (m.HasParameter("Meter.Watts.Hour"))
            statusParts.Add("Watthour: " + Fmt(m.Parameter("Meter.Watts.Hour").DecimalValue, "W/h"));

        if (m.HasParameter("Sensor.DoorWindow"))
            statusParts.Add("Door/Window: " + (m.Parameter("Sensor.DoorWindow").DecimalValue > 0 ? "Open" : "Closed"));

        // 3. ACTUATORS (Lights, Switches, Dimmer, Shutters)
        // Reports live state (ON/OFF/%) for the system status update
        if (m.HasParameter("Status.Level"))
        {
            var level = m.Parameter("Status.Level").DecimalValue;
            string state = (level > 0) ? "ON" : "OFF";

            // Append percentage for dimmers or color lights
            if (level > 0 && level <= 1) state = "ON"; // Standard binary
            else if (level > 1) state += $" ({level}%)";

            statusParts.Add("State: " + state);
        }

        // Final fallback to ensure the AI knows the device is reachable
        if (statusParts.Count == 0) statusParts.Add("Status: Online");

        return $"{m.Instance.Name}: {string.Join(", ", statusParts)}";
    }
}

ProgramBlock.ScriptSetup:
var systemPromptFile = Path.Combine(Data.GetFolder(), "gemini_system_prompt.txt");

Program.Setup(() => {
    // Register this program as Automation Manager
    Program.Implements(
        "@AI:Automan",
        "AI.Automan/Gemini"
    ).AddOption("ApiKey", "", "1. Google Gemini AI API key", "password")
     .AddOption("ModelId", "gemini-2.5-flash", "2. Model ID", "text")
     .AddOption("EnableDeepKnowledge", "On", "3. Enable Deep Knowledge (Read programs & widgets)", "checkbox")
     .AddOption("SystemInstructions", "", "4. System Instructions", $"editor:file:{systemPromptFile}:markdown");
});

Program.Run();

ProgramBlock.ScriptSource:
// ===================================================================
// GEMINI AUTOMAN - ASYNC QUEUE & DEBOUNCING
// ===================================================================

string API_URL = "AI.Automan/Gemini";
string geminiApiKey = Program.Option("ApiKey").Value.Trim();
string geminiModelId = Program.Option("ModelId").Value.Trim();
bool useDeepKnowledge = Program.Option("EnableDeepKnowledge").Value == "On";
string storeId = Program.Module.Address;

if (geminiApiKey.Length != 39 || !geminiApiKey.StartsWith("AIzaSy") || string.IsNullOrEmpty(geminiModelId)) {
    Program.Emit("Status.Init", "NotConfigured");
} else {
    Program.Emit("Status.Init", "Ready");
}

bool reconfigureRequired = false;

When.ModuleParameterChanged((module, parameter) => {
    if (module.Instance == Program.Module && parameter.Name.StartsWith("ConfigureOptions.")) {
        reconfigureRequired = true;
    }

    string childId = module.Instance.Address;
    string childName = module.Instance.Name;
    // REACTIVE MONITORING AND AUTO-CLEANUP
    if (parameter.Name == "Automan.Program.Status") {
        string childStatus = parameter.Value;
        // We only log states other than Completed to avoid spam
        Program.Log.Info($"Child program '{childName}' (ID: {childId}) reports status: '{childStatus}'");
    } else if (parameter.Name == "Automan.Program.Request" && parameter.Value.ToLower() == "quit") {
        Program.Log.Info($"Received 'Quit' signal from '{childName}' (ID: {childId}). Starting auto-cleanup...");
        try {
            Api.Call("HomeAutomation.HomeGenie/Automation/Programs.Disable/" + childId);
            Program.Log.Info($"Child program {childId} successfully disabled.");
        } catch (Exception ex) {
            Program.Log.Error($"Error disabling child program {childId}: {ex.Message}");
        }
    }

    return true;
});

// Cache & Deep Knowledge Management Variables
string currentCacheName = "";
DateTime cacheExpiration = DateTime.MinValue;

Func<string, string> GetSlimmedXml = (filePath) => {
    if (!File.Exists(filePath)) return "";
    try {
        var doc = new System.Xml.XmlDocument();
        doc.Load(filePath);
        StringBuilder sb = new StringBuilder();
        foreach (System.Xml.XmlNode pg in doc.SelectNodes("//ProgramBlock[IsEnabled='true']")) {
            string name = pg.SelectSingleNode("Name")?.InnerText ?? "Unnamed";
            string setup = pg.SelectSingleNode("ScriptSetup")?.InnerText ?? "";
            string source = pg.SelectSingleNode("ScriptSource")?.InnerText ?? "";
            if (string.IsNullOrWhiteSpace(source) && string.IsNullOrWhiteSpace(setup)) continue;
            sb.AppendLine($"PROGRAM: {name}");
            if (!string.IsNullOrWhiteSpace(setup)) sb.AppendLine("SETUP:\n" + setup);
            if (!string.IsNullOrWhiteSpace(source)) sb.AppendLine("SOURCE:\n" + source);
            sb.AppendLine("---");
        }
        return sb.ToString();
    } catch { return "Error slimming XML..."; }
};

Func<string> BuildContext = () => {
    var promptFile = Path.Combine(Data.GetFolder(), "gemini_system_prompt.txt");
    string context = "";
    try { context = File.ReadAllText(promptFile); } catch { context = "You are a HomeGenie developer."; }

    if (useDeepKnowledge) {
        StringBuilder sb = new StringBuilder();
        sb.AppendLine(context);
        sb.AppendLine("\n=======================================================");
        sb.AppendLine("HOMEGENIE SYSTEM SOURCE CODE (REFERENCE MATERIAL)");
        sb.AppendLine("=======================================================\n");

        try {
            string programsFile = Path.Combine("./", "programs.xml");
            if (File.Exists(programsFile)) {
                sb.AppendLine("--- FILE: programs.xml (C# Backend Logic) ---");
                sb.AppendLine(GetSlimmedXml(programsFile));
                sb.AppendLine("---------------------------------------------\n");
            }
        } catch (Exception ex) { Program.Log.Warn("Could not read programs.xml: " + ex.Message); }

        context = sb.ToString();
    }

    context += "\n\nIMPORTANT INSTRUCTIONS FOR Automan:\n" +
    "You are the HomeGenie Automan (Automation Manager). You must create an autonomous C# automation program based on the user's request.\n" +
    "- Provide a clear Name, Setup code, and Main code.\n" +
    "- You MUST use `Program.Emit(\"Automan.Program.Status\", \"Running\");` inside your Main block to report your state.\n" +
    "- Return ONLY valid C# code. Do NOT generate UI widgets.";

    return context;
};

DateTime rateLimitResetTime = DateTime.MinValue;
bool isQuotaExceeded = false;

Func<string, bool> EnsureCache = (fullContext) => {
    if (!useDeepKnowledge) return false;
    if (!string.IsNullOrEmpty(currentCacheName) && DateTime.UtcNow < cacheExpiration) return true;

    Program.Log.Info("Uploading context to Gemini Cache...");
    var cacheUrl = $"https://generativelanguage.googleapis.com/v1beta/cachedContents?key={geminiApiKey}";
    var cachePayload = new {
        model = $"models/{geminiModelId}",
        system_instruction = new { parts = new[] { new { text = fullContext } } },
        ttl = "3600s"
    };

    try {
        var data = Net.WebService(cacheUrl).AddHeader("Content-Type", "application/json").Post(JsonConvert.SerializeObject(cachePayload)).GetData();
        if (data != null && data.name != null) {
            currentCacheName = data.name.ToString();
            cacheExpiration = DateTime.UtcNow.AddMinutes(55);
            return true;
        }
    } catch { currentCacheName = ""; }
    return false;
};

// ===================================================================
// THE CENTRAL GENERATION ENGINE (AUTOMAN)
// ===================================================================
Func<string, bool, string> ProcessPrompt = (userCommand, isBackground) => {
    var result = Api.Call("System.Utility/ChatHistory/Get", new { StoreId = storeId });
    var payloadContents = new List<ChatMessage>();
    if (result != null) {
        payloadContents = JArray.FromObject(result).ToObject<List<ChatMessage>>();
    }

    string displayCommand = isBackground ? $"[Scheduled Task]\n{userCommand}" : userCommand;
    var userMessage = ChatMessage.Create("user", displayCommand);

    Api.Call("System.Utility/ChatHistory/Add", new { StoreId = storeId, Message = userMessage });
    payloadContents.Add(userMessage);

    string fullContext = BuildContext();
    bool hasCache = EnsureCache(fullContext);

    var genConfig = new {
        temperature = 0.2,
        response_mime_type = "application/json",
        response_schema = new {
            type = "object",
            properties = new {
                explanation = new { type = "string" },
                name = new { type = "string" },
                language = new { type = "string", @enum = new[] { "csharp", "python", "javascript" } },
                setup = new { type = "string" },
                main = new { type = "string" },
                context = new { type = "string" }
            },
            required = new[] { "explanation", "name", "setup", "main" }
        }
    };

    int maxAttempts = 5; 
    int currentAttempt = 1;
    bool isDeployed = false;
    string programId = "";
    string finalUiResponse = "";

    List<string> explanationsList = new List<string>();

    while (currentAttempt <= maxAttempts && !isDeployed)
    {
        object payload;
        if (hasCache) {
            payload = new { contents = payloadContents, cached_content = currentCacheName, generationConfig = genConfig };
        } else {
            payload = new { contents = payloadContents, system_instruction = new { parts = new[] { new { text = fullContext } } }, generationConfig = genConfig };
        }

        try
        {
            string payloadJson = JsonConvert.SerializeObject(payload, new JsonSerializerSettings { NullValueHandling = NullValueHandling.Ignore });
            string requestUrl = $"https://generativelanguage.googleapis.com/v1beta/models/{geminiModelId}:generateContent?key={geminiApiKey}";

            var data = Net.WebService(requestUrl).WithTimeout(120).AddHeader("Content-Type", "application/json").Post(payloadJson).GetData();

            if (data != null && data.candidates != null && data.candidates.Count > 0)
            {
                string rawResponse = data.candidates[0].content.parts[0].text;
                var jsonObj = JObject.Parse(rawResponse);

                string pExplanation = jsonObj["explanation"]?.ToString() ?? "";
                string pName = jsonObj["name"]?.ToString() ?? "Automan_Generated_Program";
                string pLanguage = jsonObj["language"]?.ToString() ?? "csharp";

                string pContext = jsonObj["context"]?.ToString() ?? "";
                string pSetup = jsonObj["setup"]?.ToString() ?? "";
                string pMain = jsonObj["main"]?.ToString() ?? "";
                if (!string.IsNullOrWhiteSpace(pExplanation)) {
                    explanationsList.Add(pExplanation);
                }

                // Phase 1: Program Creation
                string programDescription = explanationsList.FirstOrDefault() ?? ""; // use always the initial description
                if (string.IsNullOrEmpty(programId)) {
                    string programBlockJson = JsonConvert.SerializeObject(new { Type = pLanguage, Group = "Automan", Name = $"{pName}", Description = $"{programDescription}", IsEnabled = false });
                    var addRes = Api.Call("HomeAutomation.HomeGenie/Automation/Programs.Add", programBlockJson);
                    if (addRes != null) {
                        string resStr = addRes is string ? (string)addRes : JsonConvert.SerializeObject(addRes);
                        var jRes = JObject.Parse(resStr);
                        programId = jRes["ResponseValue"]?.ToString() ?? jRes["response"]?["ResponseValue"]?.ToString();
                    }
                }

                // Check for valid ID extraction
                if (string.IsNullOrEmpty(programId)) {
                    var errorPayload = new {
                        automan_deploy = new {
                            status = "error",
                            error_message = "Critical Error: Unable to extract the ID of the newly created program."
                        }
                    };
                    finalUiResponse = JsonConvert.SerializeObject(errorPayload, Formatting.Indented);
                    break;
                }

                // Phase 2: Compilation and Code Injection
                string compilePayloadJson = JsonConvert.SerializeObject(new { Type = pLanguage, Address = int.Parse(programId), Group = "Automan", Name = $"{pName}", Description = $"{programDescription}", ScriptSetup = pSetup, ScriptSource = pMain, ScriptContext = pContext, IsEnabled = false });
                var compileRes = Api.Call("HomeAutomation.HomeGenie/Automation/Programs.Compile", compilePayloadJson);

                bool hasCompilerErrors = false;
                string errorString = "";

                if (compileRes != null) {
                    try {
                        string resStr = compileRes is string ? (string)compileRes : JsonConvert.SerializeObject(compileRes);
                        var jToken = JToken.Parse(resStr);
                        JToken compilerOutput = null;

                        if (jToken.Type == JTokenType.Array) compilerOutput = jToken;
                        else if (jToken.Type == JTokenType.Object) compilerOutput = jToken["ResponseValue"] ?? jToken["response"]?["ResponseValue"];

                        if (compilerOutput != null && compilerOutput.Type == JTokenType.Array && compilerOutput.HasValues) {
                            hasCompilerErrors = true;
                            errorString = string.Join("\n", compilerOutput.Select(e => e.ToString()));
                        }
                    } catch (Exception ex) { Program.Log.Warn($"Compiler output parsing failed: {ex.Message}"); }
                }

                // Phase 3: Self-Healing or Deployment
                if (hasCompilerErrors)
                {
                    Program.Log.Warn($"Attempt {currentAttempt} failed. Errors: {errorString}");
                    payloadContents.Add(ChatMessage.Create("model", rawResponse));
                    payloadContents.Add(ChatMessage.Create("user", $"COMPILATION FAILED with the following errors:\n{errorString}\n\nPlease fix the C# code. Ensure variables exist and syntax is correct. Return the complete corrected JSON."));
                    currentAttempt++;
                    Pause(10);
                }
                else
                {
                    isDeployed = true;
                    Api.Call("HomeAutomation.HomeGenie/Automation/Programs.Enable/" + programId);

                    // Generate structured success metadata
                    var successPayload = new {
                        automan_deploy = new {
                            status = "success",
                            program_id = programId,
                            name = pName,
                            language = pLanguage,
                            explanation = pExplanation,
                            attempts = currentAttempt
                        }
                    };
                    finalUiResponse = JsonConvert.SerializeObject(successPayload, Formatting.Indented);

                    var modelResponse = ChatMessage.Create("model", finalUiResponse);
                    Api.Call("System.Utility/ChatHistory/Add", new { StoreId = storeId, Message = modelResponse });

                    Program.Emit("Widget.Refresh", "history_updated");
                }
            } else { break; }
        }
        catch (Exception ex)
        {
            Program.Log.Error($"API Error: {ex.Message}");
            if (ex.Message.Contains("(429)")) { 
                isQuotaExceeded = true; 
                rateLimitResetTime = DateTime.UtcNow.AddMinutes(2);
                if (isBackground) throw; // Rethrow to re-queue the task

                var quotaPayload = new {
                    automan_deploy = new {
                        status = "quota_exceeded",
                        error_message = "Rate limit reached (429). The system is pausing requests."
                    }
                };
                finalUiResponse = JsonConvert.SerializeObject(quotaPayload, Formatting.Indented);
            }
            else 
            {
                var sysErrorPayload = new {
                    automan_deploy = new {
                        status = "error",
                        error_message = $"System Error: {ex.Message}"
                    }
                };
                finalUiResponse = JsonConvert.SerializeObject(sysErrorPayload, Formatting.Indented);
            }
            break;
        }
    }

    // Final fallback if all retry attempts fail
    if (!isDeployed && string.IsNullOrEmpty(finalUiResponse)) {
        var failPayload = new {
            automan_deploy = new {
                status = "compile_failed",
                attempts = maxAttempts,
                error_message = $"Deploy Failure. Failed to generate valid code after {maxAttempts} attempts."
            }
        };
        finalUiResponse = JsonConvert.SerializeObject(failPayload, Formatting.Indented);
        Api.Call("System.Utility/ChatHistory/Add", new { StoreId = storeId, Message = ChatMessage.Create("model", finalUiResponse) });
    }

    return finalUiResponse;
};

List<string> taskQueue = new List<string>();
object queueLock = new object();

Api.Handle($"{API_URL}/Prompt.Submit", (userCommand) => {
    if (isQuotaExceeded && DateTime.UtcNow < rateLimitResetTime) {
        return new ResponseText($"**AI Temporarily Unavailable:** Rate limit reached.");
    }
    var request = Api.Parse(userCommand);
    var data = userCommand is string ? WebUtility.UrlDecode(userCommand as string) : request?.Data is string ? request?.Data as string : Encoding.Default.GetString(request?.Data as byte[]);
    string response = ProcessPrompt(data, false);
    return new ResponseText(response);
});

// Agentic task scheduling
Api.Handle($"{API_URL}/Prompt.Schedule", (userCommand) => {
    var request = Api.Parse(userCommand);
    var data = userCommand is string ? WebUtility.UrlDecode(userCommand as string) : request?.Data is string ? request?.Data as string : Encoding.Default.GetString(request?.Data as byte[]);
    lock (queueLock) {
        taskQueue.Add(data);
    }
    Program.Log.Info($"New task queued. Tasks waiting: {taskQueue.Count}");
    return new ResponseText("Task scheduled successfully.");
});

Api.Handle($"{API_URL}/{API_HISTORY_GET}", (p) => Api.Call("System.Utility/ChatHistory/Get", new { StoreId = storeId }));
Api.Handle($"{API_URL}/{API_HISTORY_CLEAR}", (p) => Api.Call("System.Utility/ChatHistory/Clear", new { StoreId = storeId }));
Api.Handle($"{API_URL}/{API_HISTORY_REMOVE_AT}", (i) => Api.Call("System.Utility/ChatHistory/RemoveAt", new { StoreId = storeId, Index = i }));
Api.Handle($"{API_URL}/{API_HISTORY_EXPORT}", (p) => Api.Call("System.Utility/ChatHistory/Export", new { StoreId = storeId }));
Api.Handle($"{API_URL}/{API_HISTORY_IMPORT}", (p) => Api.Call("System.Utility/ChatHistory/Import", new { StoreId = storeId, Data = (p as dynamic).Data }));

// ===================================================================
// AUTOMAN WORKER
// ===================================================================
while (Program.IsRunning && !reconfigureRequired) {

    if (isQuotaExceeded) {
        if (DateTime.UtcNow < rateLimitResetTime) {
            Pause(5);
            continue;
        } else {
            isQuotaExceeded = false;
            Program.Log.Info($"429 rate limit expired. Restarting queue.");
        }
    }

    string nextTask = null;
    lock (queueLock) {
        if (taskQueue.Count > 0) {
            nextTask = taskQueue[0];
            taskQueue.RemoveAt(0); // (FIFO)
        }
    }

    if (nextTask != null) {
        Program.Log.Info($"Dequeued new task...");
        try {
            ProcessPrompt(nextTask, true);
            Pause(3);
        } catch (Exception ex) {
            if (ex.Message.Contains("(429)")) {
                Program.Log.Warn($"Rate limit hitted. Re-queuing task.");
                lock (queueLock) {
                    taskQueue.Insert(0, nextTask);
                }
            } else {
                Program.Log.Error($"Critical error executing task: {ex.Message}");
            }
        }
    }

    Pause(1);
}

