ProgramBlock.ScriptSource:
// ===================================================================
// GEMINI WIDGET GENIE - WITH DEEP KNOWLEDGE & CACHING
// ===================================================================

string API_URL = "AI.WidgetGenie/Gemini";
string geminiApiKey = Program.Option("ApiKey").Value.Trim();
string geminiModelId = Program.Option("ModelId").Value.Trim();
bool useDeepKnowledge = Program.Option("EnableDeepKnowledge").Value == "On";

if (geminiApiKey.Length != 39 || !geminiApiKey.StartsWith("AIzaSy") || string.IsNullOrEmpty(geminiModelId)) {
    Program.Emit("Status.Init", "NotConfigured");
} else {
    Program.Emit("Status.Init", "Ready");
}

bool reconfigureRequired = false;
When.ModuleParameterChanged((module, parameter) => {
  if (module.Instance == Program.Module && parameter.Name.StartsWith("ConfigureOptions.")) {
    reconfigureRequired = true;
  }
  return true;
});

string storeId = Program.Module.Address;

// Cache Management Variables
string currentCacheName = "";
DateTime cacheExpiration = DateTime.MinValue;
Func<string, string> GetSlimmedXml = (filePath) => {
    if (!File.Exists(filePath)) return "";
    try {
        var doc = new System.Xml.XmlDocument();
        doc.Load(filePath);
        StringBuilder sb = new StringBuilder();
        var programs = doc.SelectNodes("//ProgramBlock");
//        foreach (System.Xml.XmlNode pg in programs) {
        foreach (System.Xml.XmlNode pg in doc.SelectNodes("//ProgramBlock[IsEnabled='true']")) {
            string name = pg.SelectSingleNode("Name")?.InnerText ?? "Unnamed";
            string setup = pg.SelectSingleNode("ScriptSetup")?.InnerText ?? "";
            string source = pg.SelectSingleNode("ScriptSource")?.InnerText ?? "";

            if (string.IsNullOrWhiteSpace(source) && string.IsNullOrWhiteSpace(setup)) continue;

            sb.AppendLine($"PROGRAM: {name}");
            if (!string.IsNullOrWhiteSpace(setup)) sb.AppendLine("SETUP:\n" + setup);
            if (!string.IsNullOrWhiteSpace(source)) sb.AppendLine("SOURCE:\n" + source);
            sb.AppendLine("---");
        }
        return sb.ToString();
    } catch {
        return "Error slimming XML, fallback to raw read...";
    }
};
// --- FUNCTION: BUILD DEEP CONTEXT ---
Func<string> BuildContext = () => {
    var promptFile = Path.Combine(Data.GetFolder(), "gemini_system_prompt.txt");
    string context = "";
    try { context = File.ReadAllText(promptFile); } catch { context = "You are a HomeGenie developer."; }

    if (useDeepKnowledge) {
        Program.Log.Info("Building Deep Knowledge Context...");
        StringBuilder sb = new StringBuilder();
        sb.AppendLine(context);
        sb.AppendLine("\n=======================================================");
        sb.AppendLine("HOMEGENIE SYSTEM SOURCE CODE (REFERENCE MATERIAL)");
        sb.AppendLine("=======================================================\n");

        // 1. Read programs.xml
        try {
            string hgRoot = Path.GetFullPath(Path.Combine(Data.GetFolder(), "..", ".."));
            string programsFile = Path.Combine("./", "programs.xml");
            if (File.Exists(programsFile)) {
                sb.AppendLine("--- FILE: programs.xml (C# Backend Logic) ---");
                sb.AppendLine(GetSlimmedXml(programsFile));
                sb.AppendLine("---------------------------------------------\n");
            }
        } catch (Exception ex) { Program.Log.Warn("Could not read programs.xml: " + ex.Message); }

        // 2. Read Widgets (HTML, CSS, JS)
        try {
            string programRoot = Path.GetFullPath(Path.Combine(Data.GetFolder(), "..", ".."));
            // Adjust the path to where your widgets actually are (e.g. html/widgets)
            string widgetsFolder = Path.Combine(programRoot, "widgets");

            if (Directory.Exists(widgetsFolder)) {
                var extensions = new[] { ".html", ".css", ".js" };
                var files = Directory.GetFiles(widgetsFolder, "*.*", SearchOption.AllDirectories)
                                     .Where(f => extensions.Contains(Path.GetExtension(f).ToLower()));

                foreach (var file in files) {
                    string relativePath = file.Replace(widgetsFolder, "").TrimStart(Path.DirectorySeparatorChar);
                    sb.AppendLine($"--- FILE: {relativePath} ---");
                    sb.AppendLine(File.ReadAllText(file));
                    sb.AppendLine($"--- END FILE: {relativePath} ---\n");
                }
            }
        } catch (Exception ex) { Program.Log.Warn("Could not read widgets: " + ex.Message); }

        context = sb.ToString();
    }
    return context;
};

// --- FUNCTION: CREATE CACHE ---
DateTime rateLimitResetTime = DateTime.MinValue;
bool isQuotaExceeded = false;
Func<string, bool> EnsureCache = (fullContext) => {
    if (!useDeepKnowledge) return false;
    if (!string.IsNullOrEmpty(currentCacheName) && DateTime.UtcNow < cacheExpiration) return true;

    Program.Log.Info("Uploading context to Gemini Cache...");
    var cacheUrl = $"https://generativelanguage.googleapis.com/v1beta/cachedContents?key={geminiApiKey}";

    var cachePayload = new {
        model = $"models/{geminiModelId}",
        system_instruction = new { parts = new[] { new { text = fullContext } } },
        ttl = "3600s"
    };

    try {
        var data = Net.WebService(cacheUrl)
            .AddHeader("Content-Type", "application/json")
            .Post(JsonConvert.SerializeObject(cachePayload))
            .GetData();

        if (data != null && data.name != null) {
            currentCacheName = data.name.ToString();
            cacheExpiration = DateTime.UtcNow.AddMinutes(55);
            Program.Log.Info($"Cache created successfully: {currentCacheName}");
            return true;
        }
    } catch (Exception ex) {
        if (ex.Message.Contains("429")) {
            Program.Log.Warn("Gemini Cache Quota exceeded (429). Using standard mode (no cache).");
        } else {
            Program.Log.Warn($"Caching failed: {ex.Message}");
        }
        currentCacheName = "";
    }
    return false;
};

// ===================================================================
// API HANDLER: Process a new user message
// ===================================================================
Api.Handle($"{API_URL}/Prompt.Submit", (userCommand) =>
{
    var request = Api.Parse(userCommand);
    var msg = userCommand is string ? WebUtility.UrlDecode(userCommand as string) : request?.Data is string ? request?.Data as string : Encoding.Default.GetString(request?.Data as byte[]);

    if (isQuotaExceeded && DateTime.UtcNow < rateLimitResetTime) {
        return new ResponseText($"**AI Temporarily Unavailable:** Rate limit reached (Error 429). Please try again in {Math.Ceiling((rateLimitResetTime - DateTime.UtcNow).TotalMinutes)} minutes.");
    }

    var result = Api.Call("System.Utility/ChatHistory/Get", new { StoreId = storeId });
    var payloadContents = JArray.FromObject(result).ToObject<List<ChatMessage>>();

    var userMessage = ChatMessage.Create("user", msg);
    Api.Call("System.Utility/ChatHistory/Add", new { StoreId = storeId, Message = userMessage });
    payloadContents.Add(userMessage);

    string fullContext = BuildContext();
    bool hasCache = EnsureCache(fullContext);
    if (isQuotaExceeded) {
        return new ResponseText("**Quota Error:** Could not load the context. Please try again in a few minutes.");
    }

    // Build the Generation Config forcing JSON output
    var genConfig = new {
        temperature = 0.2,
        response_mime_type = "application/json",
        response_schema = new {
            type = "object",
            properties = new {
                explanation = new { type = "string" },
                solution_type = new { type = "string", @enum = new[] { "widget", "automation" } },
                language = new { type = "string", @enum = new[] { "csharp", "javascript", "python" } },
                widget = new {
                    type = "object",
                    properties = new {
                        html = new { type = "string" },
                        css = new { type = "string" },
                        javascript = new { type = "string" }
                    },
                    required = new[] { "html", "css", "javascript" }
                },
                automation = new {
                    type = "object",
                    properties = new {
                        setup = new { type = "string", description = "AddOption and Program.Run() only" },
                        main = new { type = "string", description = "Core logic and listeners (MANDATORY)" },
                        context = new { type = "string" }
                    },
                    required = new[] { "setup", "main" }
                }
            },
            required = new[] { "explanation", "solution_type", "language" }
        }
    };

    // Construct Payload dynamically based on cache status
    object payload;
    if (hasCache) {
        payload = new {
            contents = payloadContents,
            cached_content = currentCacheName,
            generationConfig = genConfig
        };
    } else {
        payload = new {
            contents = payloadContents,
            system_instruction = new { parts = new[] { new { text = fullContext } } },
            generationConfig = genConfig
        };
    }

    try
    {
        string payloadJson = JsonConvert.SerializeObject(payload, new JsonSerializerSettings { NullValueHandling = NullValueHandling.Ignore });
        string requestUrl = $"https://generativelanguage.googleapis.com/v1beta/models/{geminiModelId}:generateContent?key={geminiApiKey}";

        var data = Net.WebService(requestUrl).WithTimeout(120).AddHeader("Content-Type", "application/json").Post(payloadJson).GetData();
        if (data != null && data.candidates != null && data.candidates.Count > 0)
        {
            string rawResponse = data.candidates[0].content.parts[0].text;

            if (!string.IsNullOrEmpty(rawResponse))
            {
                var jsonObj = JObject.Parse(rawResponse);
                StringBuilder formattedResponse = new StringBuilder();

                formattedResponse.AppendLine(jsonObj["explanation"]?.ToString());

                string type = jsonObj["solution_type"]?.ToString();
                string lang = jsonObj["language"]?.ToString() ?? "javascript";

                if (type == "widget") {
                    var w = jsonObj["widget"];
                    if (w != null) {
                        string html = w["html"]?.ToString() ?? "";
                        string css = w["css"]?.ToString() ?? "";
                        string js = w["javascript"]?.ToString() ?? "";

                        // Fallback
                        if (string.IsNullOrWhiteSpace(css)) {
                            css = "@import 'assets/styles/widget-ui.css';\n@import 'assets/styles/flex-layout-attribute.min.css';";
                        }

                        if (!string.IsNullOrWhiteSpace(html)) formattedResponse.AppendLine($"\n```html\n{html}\n```");
                        formattedResponse.AppendLine($"\n```css\n{css}\n```"); // Lo mettiamo sempre
                        if (!string.IsNullOrWhiteSpace(js)) formattedResponse.AppendLine($"\n```javascript\n{js}\n```");
                    }
                } else if (type == "automation") {
                    var a = jsonObj["automation"];
                    if (a != null) {
                        // 1. Setup: UI Options and Initializations
                        if (!string.IsNullOrWhiteSpace(a["setup"]?.ToString()))
                            formattedResponse.AppendLine($"\n**Setup:**\n```{lang}\n{a["setup"]}\n```");

                        // 2. Main: The core logic (Refactored from "source")
                        if (!string.IsNullOrWhiteSpace(a["main"]?.ToString()))
                            formattedResponse.AppendLine($"\n**Main:**\n```{lang}\n{a["main"]}\n```");

                        // 3. Context: Optional, typically for C# classes/methods
                        if (!string.IsNullOrWhiteSpace(a["context"]?.ToString()))
                            formattedResponse.AppendLine($"\n**Context:**\n```{lang}\n{a["context"]}\n```");
                    }
                }

                string finalReply = formattedResponse.ToString();

                var modelResponse = ChatMessage.Create("model", finalReply);
                Api.Call("System.Utility/ChatHistory/Add", new { StoreId = storeId, Message = modelResponse });

                return new ResponseText(finalReply);
            }
        }
        return new ResponseText("**Error:** The AI returned an empty response.");
    }
    catch (Exception ex)
    {
        if (ex.Message.Contains("(429)")) {
            isQuotaExceeded = true;
            rateLimitResetTime = DateTime.UtcNow.AddMinutes(2);
            return new ResponseText("**Errore 429:** Troppe richieste in corso. Ho messo in pausa le interrogazioni per un paio di minuti.");
        }
        Program.Log.Error($"Gemini API Error: {ex.Message}");
        return new ResponseText($"**Error:** Could not contact Gemini service. `{ex.Message}`");
    }
});

// APIs for Chat History
Api.Handle($"{API_URL}/{API_HISTORY_GET}", (p) => Api.Call("System.Utility/ChatHistory/Get", new { StoreId = storeId }));
Api.Handle($"{API_URL}/{API_HISTORY_CLEAR}", (p) => Api.Call("System.Utility/ChatHistory/Clear", new { StoreId = storeId }));
Api.Handle($"{API_URL}/{API_HISTORY_REMOVE_AT}", (i) => Api.Call("System.Utility/ChatHistory/RemoveAt", new { StoreId = storeId, Index = i }));
Api.Handle($"{API_URL}/{API_HISTORY_EXPORT}", (p) => Api.Call("System.Utility/ChatHistory/Export", new { StoreId = storeId }));
Api.Handle($"{API_URL}/{API_HISTORY_IMPORT}", (p) => Api.Call("System.Utility/ChatHistory/Import", new { StoreId = storeId, Data = (p as dynamic).Data }));

while (Program.IsRunning && !reconfigureRequired) { Pause(1); }

